    if (!response.ok) {
      return parseApiError(response);
    }

    return parseJson<ApiListResponse<BOMItemData>>(response);
  }

  /**
   * PATCH /api/bom/items/[id]
   *
   * Update a single BOM item.
   */
  async updateBOMItem(
    id: string,
